)

// TestProfileApplicationWithMocks runs tests against the profileApplication function.
func TestProfileApplicationWithMocks(t *testing.T) {
	tests := []struct {
		name                 string
		duration             string
		rate                 string
		directoryExists      bool
		directoryExistsError error
		mkdirAllErr          error
		createCPUErr         error
		createMemErr         error
		startCPUProfileErr   error
		writeHeapProfileErr  error
		waitForStopProfile   bool
		expectedMkdir        bool
		expectedCPUCreate    bool
		expectedMemCreate    bool
		expectedCreateCalls  int // Number of times Create is expected to be called
		expectedStatus       int
	}{
		{
			name:                "default duration and rate",
			duration:            "",
			rate:                "",
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			expectedMemCreate:   true,
			waitForStopProfile:  true,
			expectedCreateCalls: 2,
			expectedStatus:      http.StatusOK,
		},
		{
			name:                "profile rate is an invalid value",
			duration:            "1",
			rate:                "invalid", // Non-integer value
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			expectedMemCreate:   true,
			waitForStopProfile:  true,
			expectedCreateCalls: 2,             // Both file creations are attempted
			expectedStatus:      http.StatusOK, // Assuming the application defaults to the standard rate on invalid input
		},
		{
			name:                "profile rate is greater than maxProfileRate",
			duration:            "1",
			rate:                "1000", // Exceeds the suggested max rate of 500
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			expectedMemCreate:   true,
			waitForStopProfile:  true,
			expectedCreateCalls: 2,
			expectedStatus:      http.StatusOK, // Assuming the application caps the rate at 500 and proceeds
		},
		{
			name:                "profile rate is different than the default profile rate",
			duration:            "1",
			rate:                "200", // A valid, non-default rate
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			expectedMemCreate:   true,
			waitForStopProfile:  true,
			expectedCreateCalls: 2,
			expectedStatus:      http.StatusOK, // Assuming the application accepts this custom rate and proceeds
		},
		{
			name:                 "DirectoryExists error",
			duration:             "1",
			directoryExistsError: os.ErrNotExist,
			expectedStatus:       http.StatusInternalServerError,
		},
		{
			name:                "mkdirAll error",
			duration:            "1",
			mkdirAllErr:         os.ErrPermission,
			expectedMkdir:       true,
			expectedCreateCalls: 0,
			expectedStatus:      http.StatusInternalServerError,
		},
		{
			name:                "create CPU profile file error",
			duration:            "1",
			createCPUErr:        os.ErrPermission, // Simulated error on first call to Create
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			expectedCreateCalls: 1, // Attempts CPU file creation only
			expectedStatus:      http.StatusInternalServerError,
		},
		{
			name:                "StartCPUProfile returns an error",
			duration:            "1",
			startCPUProfileErr:  errors.New("CPU profiling error"),
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			waitForStopProfile:  false, // No need to wait for StopCPUProfile as it won't be called
			expectedCreateCalls: 1,     // Only attempts CPU file creation, but fails before writing
			expectedStatus:      http.StatusInternalServerError,
		},
		{
			name:                "fs.Create for memory profile returns an error",
			duration:            "1",
			createMemErr:        errors.New("Create file error"), // Simulated error on second call to Create
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			expectedMemCreate:   true,
			waitForStopProfile:  true,
			expectedCreateCalls: 2,             // Attempts both creations; the second one fails
			expectedStatus:      http.StatusOK, // This scenario still responds OK since the main operation proceeds
		},
		{
			name:                "profiler.WriteHeapProfile returns an error",
			duration:            "1",
			writeHeapProfileErr: errors.New("Write heap profile error"),
			expectedMkdir:       true,
			expectedCPUCreate:   true,
			expectedMemCreate:   true,
			waitForStopProfile:  true,
			expectedCreateCalls: 2,             // Both file creations are attempted
			expectedStatus:      http.StatusOK, // This scenario also responds OK; error in writing heap profile isn't reflected in response status
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			mockFS := &mockFileSystem.MockFileSystem{}
			mockProfiler := &mockProfiler.MockProfiler{
				WG: sync.WaitGroup{},
			}

			mockFS.On("DirectoryExists", projectPaths.TempFolderPath).
				Return(tc.directoryExists, tc.directoryExistsError)

			if tc.expectedMkdir {
				mockFS.On("MkdirAll", projectPaths.TempFolderPath, os.FileMode(0755)).Return(tc.mkdirAllErr)
			}

			// First call to Create for CPU profile
			if tc.expectedCPUCreate {
				mockFS.On(
					"Create",
					mock.MatchedBy(func(name string) bool { return strings.Contains(name, cpuProfileFileNamePrefix) })).
					Return(&os.File{}, tc.createCPUErr).
					Once()
			}

			// Second call to Create for memory profile
			if tc.expectedMemCreate {
				mockFS.On(
					"Create",
					mock.MatchedBy(func(name string) bool { return strings.Contains(name, memProfileFileNamePrefix) })).
					Return(nil, tc.createMemErr).
					Once()
			}

			mockProfiler.On("StartCPUProfile", mock.Anything).Return(tc.startCPUProfileErr).Maybe()
			mockProfiler.On("StopCPUProfile").Maybe() // "Maybe" because not reached in all scenarios
			mockProfiler.On("WriteHeapProfile", mock.Anything).Return(tc.writeHeapProfileErr).Maybe()

			r := httptest.NewRequest("POST", "/debug/profile", nil)
			q := url.Values{}
			q.Add("duration", tc.duration)
			q.Add("rate", tc.rate)
			r.URL.RawQuery = q.Encode()

			w := httptest.NewRecorder()

			profileApplication(mockFS, mockProfiler, w, r, projectPaths.TempFolderPath)

			if tc.waitForStopProfile {
				// Setup a channel to signal completion of the WaitGroup
				done := make(chan struct{})
				go func() {
					mockProfiler.WG.Wait()
					close(done)
				}()

				// Setup a timeout duration so we are not waiting indefinitely
				timeout := (defaultProfileDuration + 10) * time.Second

				// Wait for either WaitGroup completion or timeout
				select {
				case <-done:
					// WaitGroup done
				case <-time.After(timeout):
					t.Fatalf("Timed out waiting for StopCPUProfile to be called after %v", timeout)
				}
			}

			mockFS.AssertExpectations(t)
			mockProfiler.AssertExpectations(t)
			if w.Code != tc.expectedStatus {
				t.Errorf("Expected status code %d, got %d", tc.expectedStatus, w.Code)
			}
		})
	}
}
